-- ── Jekyll ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, Ruby-based static site generator that transforms plain text and templates into fast, database-free websites, and powers GitHub Pages.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Jekyll Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Jekyll review 2026: how this open-source static site generator works, key features, GitHub Pages integration, pros, cons, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Jekyll is a free, open-source static site generator written in Ruby that converts plain text, Markdown, Liquid templates, and layout files into a complete, ready-to-host static website with no database or server-side application required at runtime. It was created by Tom Preston-Werner, who co-founded GitHub in 2008 alongside Chris Wanstrath, PJ Hyett, and Scott Chacon; roughly nine months after GitHub launched, in December 2008, Preston-Werner released Jekyll because he was frustrated with the complexity of database-backed blogging platforms like WordPress and Mephisto and wanted a simpler, file-based way to publish a blog. The project was made fully open source in 2009 and reached a stable 1.0 release on May 8, 2013, by which point Jekyll had been handed off to Parker Moore, a GitHub employee who led its development and helped formalize its plugin and theme ecosystem; the project is now maintained by a community of contributors under the Jekyll organization on GitHub rather than by a single company. Jekyll's defining feature, and the primary reason for its widespread adoption, is its native integration with GitHub Pages: a developer can write content in Markdown, push it to a gh-pages branch or a repository configured for Pages, and GitHub automatically builds the Jekyll site and serves it for free at a github.io URL or a custom domain, with no separate build pipeline or hosting bill required. Beyond that integration, Jekyll supports front-matter metadata for posts and pages, the Liquid templating language (also created for Shopify) for layouts and includes, a plugin system for extending functionality (tags, generators, filters, hooks), built-in support for blog-style permalinks, categories, and tags, Sass/CSS preprocessing, incremental builds, and a local development server with live reload. Because the output is pure static HTML, CSS, and JavaScript, Jekyll sites are inherently fast, secure against most server-side attacks, cheap or free to host on any static file host (GitHub Pages, Netlify, S3, Cloudflare Pages), and simple to version-control since the entire site, content included, lives as files in a Git repository. As free and open-source software distributed under the MIT license, Jekyll has no pricing tiers, company, or headquarters; it is a community project rather than a commercial product, though many of its core contributors have historically been affiliated with GitHub. Its target audience is developers, technical writers, and documentation teams who are comfortable working in a code editor and command line and who want a lightweight, version-controllable alternative to CMS platforms like WordPress, particularly for blogs, personal sites, project documentation, and marketing pages that do not need dynamic server-side features. As of the mid-2010s Jekyll was widely cited as the most popular static site generator, largely on the strength of its GitHub Pages default status, though it now competes with a large field of alternatives including Hugo (written in Go, prized for build speed), Gatsby and Next.js (React-based, JAMstack-oriented), Eleventy (11ty, a JavaScript-based minimalist generator), and Astro, several of which have overtaken Jekyll in new-project adoption due to faster build times and modern JavaScript tooling, even as Jekyll remains deeply entrenched in existing GitHub Pages sites and Ruby-centric documentation workflows.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'df10fa66-24a3-4755-9dcd-f62b7329c9c8';

