-- ── Jellyfin ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, self-hosted media server that lets you organize and stream your own movies, TV shows, and music without subscriptions or tracking.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Jellyfin Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Jellyfin review 2026: features, self-hosting setup, apps, pros, cons, and how it compares to Plex and Emby as a free open-source media server.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Jellyfin is a free and open-source, self-hosted media server that lets individuals organize, manage, and stream their own movies, TV shows, music, photos, and live TV to any device on their network or over the internet, without subscriptions, licensing fees, telemetry, or a mandatory cloud account. The project began on December 8, 2018, when a group of users led by co-founders Andrew Rabert and Joshua Boniface forked Emby's codebase in direct response to Emby's decision to take its upcoming 4.x release closed-source. The fork was motivated by a combination of prior, previously reported GPL license violations by Emby, the introduction of a paywall for features that had been free, the removal or hiding of client and server source code, and a general lack of openness to community contributions; Rabert coined the name Jellyfin the day after the fork was agreed upon, and an initial public release followed on December 30, 2018. Technically, Jellyfin is descended from Emby's 3.5.2 codebase and was subsequently ported from the .NET Framework to .NET Core (now just .NET) to achieve full cross-platform support, allowing the server to run natively on Windows, Linux, macOS, and inside Docker containers, including on low-power hardware like a Raspberry Pi or a NAS device from Synology or QNAP. Because it has no company behind it, Jellyfin has no headquarters, no funding rounds, and no company size; it is maintained entirely by a volunteer, community-driven team of contributors and released under the GPLv2 license for the server, with client applications under varying open-source licenses. Its feature set covers automatic library organization with metadata and artwork fetching, on-the-fly and hardware-accelerated transcoding for playback on virtually any device or network condition, live TV and DVR support via tuner hardware, multi-user profiles with parental controls, a plugin architecture for extending functionality (subtitle providers, additional metadata sources, and more), and native or web-based client apps for Android, iOS, Android TV, Fire TV, Roku, tvOS, Windows, macOS, Linux, and smart TVs, alongside a browser-based web client that works on virtually any platform. Because everything is self-hosted, users retain full ownership of their media library and viewing data, with no ads, no recommendation algorithms mining behavior, and no risk of a vendor shutting down or changing pricing on them. Jellyfin's most direct competitors are Plex, a much larger commercial media server with a similar core concept but a freemium model, a paid Plex Pass tier, and increasing reliance on account-based cloud features and, more recently, advertising; and Emby, the project Jellyfin forked from, which retains a freemium model with a paid Emby Premiere tier for features like hardware transcoding and mobile sync. Jellyfin differentiates itself sharply from both by remaining entirely free, fully open source, free of a mandatory account or telemetry, and governed by its community rather than a company, which appeals strongly to privacy-conscious self-hosters, home-lab enthusiasts, and users who were alienated by Plex's or Emby's shifts toward monetization and cloud dependency. It is commonly deployed as part of a self-hosted media stack alongside tools like Sonarr, Radarr, and qBittorrent for automated library management, and is a frequent recommendation in the r/selfhosted and home-server communities as the go-to free alternative once a user decides they no longer want to pay for or depend on Plex.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '07686163-d3fa-49ec-9a3d-0f4d2664089d';

