-- ── Jelu ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, self-hostable book tracker for logging what you have read, are reading, and want to read, with metadata import and a REST API.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Jelu Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Jelu review 2026: self-hosted book tracking features, Docker setup, metadata import, pros, cons and alternatives to Goodreads and StoryGraph.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Jelu is an open-source, self-hostable book tracker and personal library application that lets readers log the books they have read, are currently reading, and want to read, along with tags, ratings, series, and reading history, without relying on a third-party commercial book-tracking service. It is developed by a maintainer active on GitHub as bayang, with the project's source published openly and released under an open-source license, and it can be self-hosted via Docker (the most common deployment path) on a home server, NAS, or VPS. The application is built around a Kotlin/Spring Boot backend with a Vue.js frontend, backed by a relational database (commonly SQLite or PostgreSQL depending on deployment scale), and it exposes a documented REST API that lets users or third-party clients programmatically add, update, and query books, series, and reading events. Core functionality centers on maintaining reading-status lists (to-read, reading, read, dropped), attaching personal ratings and notes, organizing books into series and by tags, and tracking historical reading events over time so users can see reading pace and habits. Jelu supports metadata import from external sources, letting users search and pull in book details (title, author, cover art, description, ISBN) rather than entering everything manually, and it supports importing existing libraries from common export formats used by other tracking tools, easing migration away from commercial services. Because it is self-hosted and open source, Jelu carries no license fee and no subscription cost; the only expense is whatever infrastructure a user runs it on, typically a low-cost VPS or an existing home server, and there is no vendor lock-in since the underlying data lives in a database the user controls and can export or query directly via the API. Jelu's target audience is privacy-conscious readers, home-lab and self-hosting enthusiasts, and developers who want a lightweight, ad-free, tracking-free alternative to commercial platforms like Goodreads for logging their reading habits, particularly those who already run other self-hosted services (media servers, RSS readers, etc.) and want their book data to live on the same infrastructure. Because it is self-hosted, there is no data-mining or ad-supported business model, and the REST API makes it suitable for users who want to build custom dashboards, browser extensions, or automations on top of their reading data. Its closest competitors and points of comparison are Goodreads (the dominant, Amazon-owned commercial book-tracking service, widely criticized for a dated interface and lack of API access for individual users), The StoryGraph (a modern, mood- and pace-oriented commercial reading tracker), LibraryThing (an older, community-driven cataloging service), and other self-hosted alternatives such as BookLore and Bookwyrm (a federated, ActivityPub-based reading tracker); Jelu differentiates itself from these primarily through being fully self-hosted and open source with a clean REST API, appealing to the same self-hosting audience that already runs tools like Jellyfin or Immich, at the tradeoff of lacking the social/community discovery features and large user base that Goodreads and StoryGraph offer.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ae515eae-68cb-450f-8fad-3f3174591ee1';

