-- ── JetBrains IntelliJ IDEA ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Full-featured IDE for Java and Kotlin development by JetBrains, offering intelligent code completion, refactoring, debugging, and framework support.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (core edition); Ultimate features from $199/year individual license$q$, starting_price),
  founded_year = COALESCE(2001, founded_year),
  company_size = COALESCE($q$1000-5000 employees$q$, company_size),
  headquarters = COALESCE($q$Prague, Czech Republic$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Japanese$q$, $q$Korean$q$, $q$Chinese$q$, $q$Spanish$q$, $q$German$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$IntelliJ IDEA Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$IntelliJ IDEA review 2026: Java and Kotlin IDE features, Ultimate vs free edition, pricing, pros, cons and top alternatives like Eclipse and VS Code.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$IntelliJ IDEA is a full-featured integrated development environment for Java and Kotlin development, built by JetBrains and first released in January 2001 as the company's flagship product. JetBrains was founded in 2000 in Prague, initially under the name IntelliJ Software, by three Russian software developers, Sergey Dmitriev, Valentin Kipyatkov, and Eugene Belyaev, whose first product was a Java refactoring tool called IntelliJ Renamer; the company later renamed itself JetBrains and IntelliJ IDEA became its central offering, credited with popularizing deep static-analysis-driven features like on-the-fly code inspection, safe automated refactoring, and context-aware code completion that many competing IDEs subsequently adopted. JetBrains remains headquartered in Prague, Czech Republic, at its Kavci Hory office, and has grown into a large, privately held developer-tools company with roughly 3,300 employees worldwide as of late 2025 (up from about 2,300 in 2023), distributed across offices in more than a dozen countries with particularly large teams in Germany, the Netherlands, and Cyprus; the company is known for building an entire family of IDEs beyond IntelliJ IDEA, including PyCharm, WebStorm, PhpStorm, GoLand, Rider, and CLion, plus the Kotlin programming language itself, which JetBrains created and open-sourced and which Google later endorsed as an official language for Android development. For most of its history IntelliJ IDEA was split into two editions: a free, open-source Community Edition supporting Java, Kotlin, Groovy, and Scala with basic frameworks like JavaFX and Swing, and a paid Ultimate Edition adding support for additional languages (PHP, JavaScript, TypeScript, Python, Ruby, Go, SQL) and enterprise frameworks (Spring, Jakarta EE, Hibernate, Micronaut, Quarkus) along with built-in database tools and advanced web/mobile development support, including Android tooling. In a major change announced and rolled out starting with release 2025.3 in December 2025, JetBrains unified the two editions into a single IntelliJ IDEA distribution: the IDE itself remains free for both commercial and non-commercial use with an expanded set of free core Java and Kotlin features, while what were previously Ultimate-only capabilities now require an active subscription to unlock, rather than requiring installation of a separate paid product. JetBrains sells subscriptions on a per-product or 'All Products Pack' basis, with an individual (personal-use) IntelliJ IDEA subscription priced at 199 dollars per year (or 19.90 dollars per month), dropping to 159 dollars in year two and 119 dollars in year three for continuous subscribers under JetBrains' loyalty-discount program, following a company-wide price increase of 10 to 18 percent implemented in October 2025, the first increase since 2017; organizational and commercial-use licenses are priced higher and are typically purchased per named user with volume discounts. JetBrains moved from perpetual licenses to a subscription-first model in November 2015, though a 'fallback license' rule still lets a subscriber keep using the last version they were entitled to if they maintained 12 consecutive months of subscription before cancelling. IntelliJ IDEA's target audience spans individual Java and Kotlin developers, students and open-source contributors (who qualify for free licenses), and professional and enterprise engineering teams building JVM-based backend systems, Android apps, and full-stack web applications who need the Ultimate-tier framework and database tooling. Its main competitors are Eclipse (free, open-source, older Java IDE), Visual Studio Code with Java extensions (lightweight, free, extension-driven), NetBeans, and Android Studio (itself built on the IntelliJ platform); IntelliJ IDEA differentiates itself through deeper, more accurate static analysis, safer automated refactoring, and tighter native integration with frameworks like Spring Boot, which is widely cited by professional Java developers as materially improving productivity compared with Eclipse or plain-text editors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a5a9d90c-49e0-401c-af66-b1fa6982ad32';

