INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Job posting and syndication$q$, $q$Post once and distribute openings automatically to major job boards including Indeed, ZipRecruiter, LinkedIn, and Glassdoor.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Resume parsing and candidate scoring$q$, $q$Incoming applications are automatically parsed into structured profiles, with AI-assisted fit recommendations to rank candidates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Customizable hiring workflows$q$, $q$Clone and tailor pipeline stages per role so every requisition follows a consistent, trackable process.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Interview scheduling and scorecards$q$, $q$Coordinate interviews and collect structured, comparable feedback from hiring teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$E-signature offer letters$q$, $q$Generate and send offer letters for electronic signature directly from the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Automated candidate communication$q$, $q$Trigger email sequences and screening questionnaires automatically as candidates move through the pipeline.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Reporting and analytics$q$, $q$Built-in dashboards track time-to-fill, pipeline conversion, and source-of-hire performance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Integrations marketplace$q$, $q$Connects to background-check providers, HRIS systems, calendars, and assessment tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Budget-friendly pricing compared to enterprise ATS platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Fast setup, typically live within days$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Simple interface suited to generalist HR staff, not just recruiters$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Strong job-board syndication out of the box$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Backed by Employ Inc.'s broader recruiting ecosystem for upgrade paths$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Less configurable than enterprise platforms like Greenhouse or Lever$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Advanced reporting and texting cost extra as add-ons$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Pricing is job-volume based, which can get costly for high-volume hiring$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Fewer deep native integrations than category leaders$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$AI features are narrower in scope than newer AI-first recruiting tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$What is JazzHR used for$q$, $q$JazzHR is an applicant tracking system used by small and mid-sized businesses to post jobs, screen applications, manage interview workflows, and send offer letters from one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$How much does JazzHR cost$q$, $q$JazzHR has three plans: Hero at $75/month, Plus at $269/month, and Pro at $420/month, with optional add-ons for advanced reporting ($59/month) and candidate texting (from $39/month).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Is JazzHR the same company as The Resumator$q$, $q$Yes. JazzHR began in 2009 as The Resumator, was renamed Jazz in 2015, and became JazzHR in 2016 after continued product expansion.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Who owns JazzHR now$q$, $q$JazzHR is owned by Employ Inc., a recruiting software holding company that also owns Jobvite, Lever, and NXTThing RPO, formed after Jobvite acquired JazzHR in 2021.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Does JazzHR offer a free trial$q$, $q$Yes, JazzHR offers a free trial on its plans so teams can test the hiring workflow before subscribing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$What are the best JazzHR alternatives$q$, $q$Common alternatives include Greenhouse, Lever, Breezy HR, Workable, and BambooHR's hiring module, which vary in price and configurability for larger or more complex recruiting teams.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Replacing spreadsheet-based hiring$q$, $q$Small businesses moving off shared spreadsheets and email threads gain a structured pipeline, automated parsing, and audit trail for every requisition.$q$, $q$Small business owners and office managers handling occasional hiring$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Standardizing multi-role hiring workflows$q$, $q$Growing companies with several open roles use cloneable workflows and scorecards to keep hiring consistent across departments and hiring managers.$q$, $q$HR generalists and lean talent acquisition teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Scaling recruiting without adding headcount$q$, $q$Automated job syndication, candidate communication, and reporting let a single HR person manage a higher volume of open roles.$q$, $q$SMB HR teams of one to five people$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Hero$q$, $q$$75/month$q$, $q$Monthly$q$, NULL, $q$["Single active job","Core ATS and resume parsing","Careers page","Basic reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Plus$q$, $q$$269/month$q$, $q$Monthly$q$, NULL, $q$["Multiple concurrent jobs","Workflow automation","Interview scheduling and scorecards","Job board syndication"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$Pro$q$, $q$$420/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited open jobs","Advanced customization","Premium support","E-signature offer letters"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$JazzHR is a recruiting and applicant tracking platform built specifically for small and mid-sized businesses. It replaces spreadsheets, shared inboxes, and generic project trackers with a purpose-built system for posting jobs, collecting and parsing applications, moving candidates through a hiring pipeline, and collaborating with hiring managers and interviewers.$q$, $q$Originally launched in 2009 as The Resumator by founder Don Charlton, the product was rebranded twice (Jazz in 2015, then JazzHR in 2016) as it matured from a simple resume database into a full-featured ATS. Since 2021 it has operated as one of four recruiting brands under Employ Inc., alongside Jobvite, Lever, and NXTThing RPO, giving customers a path to upgrade into more advanced platforms as they scale.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, JazzHR automates the mechanics of hiring: jobs can be posted once and syndicated to dozens of job boards, incoming resumes are automatically parsed into structured candidate profiles, and hiring workflows can be cloned and customized per role so every requisition follows a consistent, auditable process. AI-assisted candidate recommendations help surface the strongest applicants without manual resume-by-resume review.$q$, $q$Beyond sourcing and screening, JazzHR includes structured interview scheduling with shareable scorecards, automated candidate communication (email templates and questionnaires), e-signature offer letters, careers-page branding, and reporting on metrics like time-to-fill and source effectiveness. Native and marketplace integrations cover background checks, HRIS/payroll handoff, calendar syncing, and assessment tools, so JazzHR can sit as the hiring hub in an otherwise disconnected SMB HR tech stack.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$JazzHR sells three named subscription tiers billed monthly: Hero ($75/month) for companies posting a single job at a time, Plus ($269/month) for teams running multiple concurrent searches with added workflow automation, and Pro ($420/month) for organizations that need unlimited open jobs, deeper customization, and premium support. All tiers include core ATS functionality such as resume parsing, pipeline management, and reporting.$q$, $q$Two optional add-ons extend any plan: advanced reporting for $59/month and candidate texting starting at $39/month. JazzHR offers a free trial so teams can evaluate the workflow before committing, and because pricing is transparent and tiered by job volume rather than by headcount or feature-gating alone, it tends to be markedly cheaper than enterprise ATS platforms like Greenhouse for comparable hiring volume.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8edc4560-4c87-4f48-9ba0-8af1a559a2e7', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Physical and virtual corporate cards$q$, $q$Issue unlimited virtual cards and physical cards with no annual fees and adjustable per-user spend limits.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Multi-currency accounts$q$, $q$Hold and transact in multiple currencies across Latin America, EMEA, and North America from one account.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Bill pay and accounts payable$q$, $q$Automate vendor payments with no registration, subscription, or monthly fees on the core account.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Short-term credit lines$q$, $q$Access financing sized to cash position and revenue rather than solely local credit history.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Real-time expense management$q$, $q$Track transactions as they happen with receipt capture and approval workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Cashback and rewards$q$, $q$Earn up to 1 percent cashback plus perks like airport lounge access and vendor vouchers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Cross-border money transfers$q$, $q$Move money internationally with competitive foreign-exchange rates and visible fees before sending.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Spend controls and permissions$q$, $q$Set and adjust limits per user or team in real time to manage budget compliance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$No annual fees on corporate cards and no subscription cost to start$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Strong multi-currency support across Latin America, EMEA, and North America$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Underwrites credit based on cash and revenue, not just local credit history$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Cashback and travel perks comparable to US-focused competitors$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Backed by well-known investors including a16z and Y Combinator$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Detailed pricing for advanced tiers requires contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Primary strength is cross-border spend, less differentiated for single-country US-only teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Foreign-exchange fees still apply on international transactions$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Newer and smaller than incumbents like Brex or Ramp in brand recognition$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Reported headquarters location varies across sources, reflecting a highly distributed operating footprint$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$What does Jeeves do$q$, $q$Jeeves is a corporate spend management platform offering multi-currency corporate cards, bill pay, expense tracking, and credit lines for companies operating across multiple countries.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Who founded Jeeves$q$, $q$Jeeves was founded in 2019 by Dileep Thazhmon and went through the Y Combinator accelerator program.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$How much does Jeeves cost$q$, $q$The core Jeeves account and card issuance are free, with the company earning revenue from card interchange and FX spreads; advanced tiers run roughly 5 to 15 dollars per user per month, and enterprise pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$How much funding has Jeeves raised$q$, $q$Jeeves has raised approximately 380 million dollars across nine rounds from investors including CRV, Andreessen Horowitz, and Y Combinator, reaching a valuation of about 2.1 billion dollars.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Which countries does Jeeves support$q$, $q$Jeeves supports companies operating in Brazil, Colombia, Mexico, other parts of Latin America, EMEA, and North America.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$What are the main alternatives to Jeeves$q$, $q$Common alternatives include Brex, Ramp, and Airbase for US-focused spend management, plus regional cross-border payment providers for Latin America and EMEA.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Issuing cards to a distributed international team$q$, $q$Finance teams issue physical and virtual cards to employees across several countries from one platform with unified spend controls.$q$, $q$Finance and operations teams at multinational startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Accessing credit without local banking history$q$, $q$Companies with strong revenue but limited local credit history use Jeeves' cash-flow-based underwriting to secure a credit line.$q$, $q$Venture-backed startups expanding into new markets$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Automating cross-border vendor payments$q$, $q$Accounts-payable teams pay international vendors and contractors in local currencies without opening accounts in each country.$q$, $q$Accounts payable and procurement teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Core$q$, $q$Free$q$, $q$No subscription fee$q$, NULL, $q$["Physical and virtual corporate cards","Basic expense tracking","Bill pay with no monthly fee","Cashback on card spend"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Growth$q$, $q$Approx. $5-15/user/month$q$, $q$Monthly$q$, NULL, $q$["Advanced spend controls","Higher credit limits","Multi-entity management","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["Custom credit lines","Dedicated account management","Advanced multi-currency treasury tools","Enterprise-grade integrations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jeeves is a financial operations platform built for companies that spend and operate across borders. Rather than forcing finance teams to stitch together separate banking relationships, card programs, and payment rails in each country, Jeeves consolidates corporate cards, bill pay, expense management, and short-term credit into one multi-currency system.$q$, $q$Founded in 2019 by Dileep Thazhmon and built through Y Combinator, Jeeves grew out of the observation that fast-growing startups outside the US, particularly in Latin America, often could not access corporate credit cards or credit lines from local banks despite having strong revenue and funding, because traditional underwriting relies on local credit history the companies simply had not built up yet.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jeeves issues physical and unlimited virtual corporate cards with adjustable spend limits, no annual fees, and cashback of up to 1 percent, alongside real-time expense tracking so finance teams can see transactions as they happen rather than reconciling weeks later. Its bill-pay and accounts-payable tools automate vendor payments across currencies without charging registration, subscription, or monthly account fees, and the platform supports short-term credit lines sized to a company's cash and revenue profile rather than local credit history alone.$q$, $q$The platform operates across multiple currencies and geographies, including Brazil, Colombia, Mexico, EMEA, and North America, letting a single finance team manage spend for entities in several countries from one dashboard. Rewards and perks such as airport lounge access and vendor vouchers are layered on top of the core card program to make Jeeves competitive with US-style corporate card rewards for globally distributed teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jeeves does not charge a flat subscription fee to open an account or issue cards; the core product is free to start, with the company earning revenue primarily through card interchange and foreign-exchange spreads on cross-border payments. This makes the entry point effectively free for companies that mainly need cards and basic expense tracking.$q$, $q$For advanced spend controls, higher credit limits, and additional users, Jeeves applies usage-based or per-user pricing that industry trackers place in the roughly 5 to 15 dollar per user per month range, while larger organizations with complex multi-entity, multi-currency needs negotiate custom enterprise pricing directly with Jeeves' sales team.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('639b380d-84c6-419b-a52a-8ad57b880d9c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
