INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Markdown and Liquid templating$q$, $q$Write content in Markdown with YAML front matter, styled through reusable Liquid layouts and includes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$GitHub Pages integration$q$, $q$Push to a configured repository and GitHub automatically builds and hosts the Jekyll site for free.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Plugin ecosystem$q$, $q$Extend builds with generators, converters, and filters contributed by the open-source community.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Blog-aware conventions$q$, $q$Built-in support for dated posts, permalinks, tags, and categories out of the box.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Static output$q$, $q$Generates plain HTML, CSS, and JS with no database or server-side runtime required.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Sass/CSS support$q$, $q$Compile Sass stylesheets as part of the build process without extra tooling.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Local development server$q$, $q$Preview changes locally with live reload before pushing to production.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Full Git version control$q$, $q$Site content and configuration live as files in a Git repo, enabling history and branch-based review.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Completely free and open source under MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Free hosting and automatic builds via GitHub Pages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Static output is fast, secure, and cheap to host anywhere$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Entire site is version-controlled in Git$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Large ecosystem of free and paid themes and plugins$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Requires comfort with Ruby, command line, and Git$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Build times can be slow on large sites compared to Hugo or Eleventy$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$No visual editor; not friendly to non-technical content editors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Ruby environment setup can be a barrier on some operating systems$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Losing ground in new-project adoption to faster JS-based generators$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$What is Jekyll used for$q$, $q$Jekyll is used to build static websites such as blogs, documentation sites, and project pages, and is the default static site generator behind GitHub Pages.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Who created Jekyll$q$, $q$Jekyll was created by GitHub co-founder Tom Preston-Werner in December 2008 and later maintained by contributors including former GitHub employee Parker Moore.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Is Jekyll free$q$, $q$Yes, Jekyll is free and open-source software licensed under the MIT license, with no paid tiers or subscription.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Does Jekyll require a database$q$, $q$No, Jekyll compiles content into static HTML, CSS, and JavaScript files ahead of time, so no database or application server is needed at runtime.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Can I host a Jekyll site for free$q$, $q$Yes, GitHub Pages hosts and automatically builds Jekyll sites at no cost, which is the most common free hosting option.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$What are the main alternatives to Jekyll$q$, $q$Popular alternatives include Hugo, Eleventy (11ty), Gatsby, Next.js, and Astro, which vary in build speed, language, and templating approach.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Publishing a developer blog$q$, $q$Write posts in Markdown and publish them for free via GitHub Pages without managing a server or database.$q$, $q$Developers and technical writers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Hosting open-source project documentation$q$, $q$Version-control documentation alongside code and deploy it automatically whenever the docs branch updates.$q$, $q$Open-source maintainers and documentation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Building a lightweight marketing or portfolio site$q$, $q$Create a fast, static personal or company site with no ongoing hosting cost or CMS maintenance.$q$, $q$Individual developers and small teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under MIT license","Unlimited sites","Community plugin and theme ecosystem","Free hosting via GitHub Pages"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jekyll is a static site generator: instead of rendering pages on every request from a database, it compiles Markdown files, templates, and configuration into plain HTML, CSS, and JavaScript ahead of time, which can then be served from any web host with no application server involved.$q$, $q$Created by GitHub co-founder Tom Preston-Werner in December 2008 and open-sourced in 2009, Jekyll became the default engine behind GitHub Pages, letting anyone publish a site for free simply by pushing Markdown files to a GitHub repository. That built-in distribution channel made it one of the most widely used static site generators for years, particularly for developer blogs, open-source project sites, and technical documentation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jekyll content is written in Markdown or HTML with YAML front matter for metadata, then assembled using the Liquid templating language into layouts and includes. It has native support for blog conventions such as dated posts, permalinks, tags, and categories, along with Sass/CSS compilation and a local server with live reload for previewing changes during development.$q$, $q$Its plugin architecture allows generators, converters, and filters to extend the build process, and because the final output is static files, Jekyll sites deploy anywhere: GitHub Pages, Netlify, Cloudflare Pages, or a basic file server. The entire site, including content, lives in a Git repository, giving writers full version history and branch-based review workflows for free.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jekyll is entirely free and open source under the MIT license, with no paid tiers, subscriptions, or company behind it charging for the software itself. The only costs a user incurs come from optional paid hosting if they choose not to use free options like GitHub Pages, or from premium third-party Jekyll themes and plugins sold by independent designers.$q$, $q$Because there is no vendor lock-in or licensing fee, the real cost of adopting Jekyll is developer time: setting up the Ruby environment, choosing or building a theme, and configuring the build pipeline, all of which is offset for many users by GitHub Pages' zero-cost hosting and automatic build integration.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
