INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('df10fa66-24a3-4755-9dcd-f62b7329c9c8', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Automatic library organization$q$, $q$Scans your media and fetches metadata and artwork automatically to build a browsable library.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Hardware-accelerated transcoding$q$, $q$Transcodes video on the fly, using GPU acceleration where available, for smooth playback on any device.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Live TV and DVR$q$, $q$Watch and record live television through supported tuner hardware.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Multi-platform client apps$q$, $q$Native apps for Android, iOS, Android TV, Fire TV, Roku, tvOS, Windows, macOS, and Linux, plus a web client.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Multi-user profiles and parental controls$q$, $q$Create separate user accounts with individual libraries, permissions, and content restrictions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Plugin architecture$q$, $q$Extend the server with community plugins for subtitles, metadata providers, and more.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$No account or telemetry required$q$, $q$Runs fully offline-capable with no mandatory cloud account and no usage tracking.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Docker and NAS support$q$, $q$Deploys easily via Docker or on NAS platforms like Synology and QNAP.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Completely free with no premium tier or paywalled features$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Fully open source under GPLv2 with community governance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$No mandatory account, telemetry, or vendor lock-in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Wide range of native client apps across platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Active community plugin ecosystem$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Requires self-hosting knowledge and your own hardware$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$No official cloud relay, so remote access setup can be more involved than Plex$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Smaller polish and UI refinement budget than commercially funded Plex$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Metadata scraping can occasionally be less reliable than Plex's agents$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$No official paid support channel since it is volunteer-run$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Is Jellyfin free$q$, $q$Yes, Jellyfin is completely free and open source with no premium tier, subscription, or paywalled features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$What is the difference between Jellyfin and Plex$q$, $q$Jellyfin is fully open source, free, and has no mandatory account or telemetry, while Plex is a commercial product with a freemium model, a paid Plex Pass tier, and cloud-account requirements.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Is Jellyfin a fork of Emby$q$, $q$Yes, Jellyfin was forked from Emby's 3.5.2 codebase in December 2018 after Emby announced it would take its next major release closed-source.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$What devices does Jellyfin support$q$, $q$Jellyfin has apps for Android, iOS, Android TV, Fire TV, Roku, tvOS, Windows, macOS, Linux, and most smart TVs, plus a browser-based web client.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Do I need a powerful server to run Jellyfin$q$, $q$A basic server or NAS can run Jellyfin for direct-play libraries; hardware transcoding for multiple simultaneous streams benefits from a more capable CPU or GPU.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Who maintains Jellyfin$q$, $q$Jellyfin is maintained entirely by a volunteer, community-driven team of open-source contributors rather than a company.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Replacing Plex or Emby subscriptions$q$, $q$Users who no longer want to pay for Plex Pass or Emby Premiere migrate their library to Jellyfin for equivalent core functionality at no cost.$q$, $q$Home media enthusiasts and cord-cutters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Building a privacy-respecting home media setup$q$, $q$Privacy-conscious users run Jellyfin to stream their own library without telemetry or a mandatory cloud account.$q$, $q$Privacy-focused self-hosters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Powering a home-lab media stack$q$, $q$Home-lab operators pair Jellyfin with tools like Sonarr and Radarr for a fully automated, self-hosted media pipeline.$q$, $q$Home-lab and self-hosting enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited libraries and users","Hardware-accelerated transcoding","Live TV and DVR support","All client apps included"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jellyfin is a self-hosted media server: software you install on your own hardware, whether a home server, NAS, or a small always-on PC, that organizes your personal collection of movies, TV shows, and music and streams it to any device on demand. It fills the same role as Plex or Emby but with no company, subscription, or account requirement behind it.$q$, $q$The project was created in December 2018 when a group of users, led by Andrew Rabert and Joshua Boniface, forked Emby's open-source codebase after Emby announced its next major version would become closed-source. Rather than accept that shift, the fork's creators committed to keeping Jellyfin permanently free and open, and the project has since grown into the most widely used fully open-source media server.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jellyfin automatically scans a media library, fetches metadata and artwork, and organizes content into a browsable interface accessible from a web browser or native apps on Android, iOS, Android TV, Fire TV, Roku, tvOS, and most smart TVs. It supports on-the-fly transcoding, including hardware-accelerated transcoding, so content plays smoothly regardless of the client device's format support or the network's bandwidth.$q$, $q$Additional capabilities include live TV and DVR support through tuner hardware, multi-user profiles with parental controls, a plugin system for extending metadata sources and functionality, and support for photos and audiobooks alongside video and music. Because Jellyfin runs entirely on hardware the user controls, there is no vendor-imposed limit on library size, device count, or feature access.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jellyfin is completely free, with every feature, including hardware transcoding, live TV, and all client apps, available at no cost and with no premium tier. It is released under the GPLv2 license for the core server, meaning the source code is open for anyone to inspect, modify, or self-host indefinitely.$q$, $q$The only ongoing cost to running Jellyfin is the hardware and electricity for the server it runs on, since there is no subscription, per-device fee, or account requirement of any kind. This stands in direct contrast to Plex's Plex Pass subscription and Emby's Emby Premiere tier, both of which gate features like hardware transcoding or mobile sync behind a paid plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('07686163-d3fa-49ec-9a3d-0f4d2664089d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
