INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Reading status tracking$q$, $q$Organize books into to-read, currently reading, read, and dropped lists.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Ratings, notes, and tags$q$, $q$Attach personal ratings, free-text notes, and custom tags to any book in your library.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Series organization$q$, $q$Group related titles into series for easier browsing and tracking of multi-book collections.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Reading history and events$q$, $q$Log historical reading events to track reading pace and habits over time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Metadata import$q$, $q$Pull in book details like cover art, author, and description from external sources automatically.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$REST API$q$, $q$Documented API for programmatic access, custom dashboards, and third-party integrations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Docker self-hosting$q$, $q$Deploy easily via Docker on a home server, NAS, or VPS with full control over your data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Library import$q$, $q$Import existing book collections from common export formats to migrate away from other tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Completely free and open source with no subscription cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Full data ownership since everything is self-hosted$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Documented REST API enables custom tooling and automation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Straightforward Docker deployment for self-hosting enthusiasts$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$No ads, tracking, or third-party data sharing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Requires self-hosting knowledge and infrastructure to run$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$No built-in social or community discovery features like Goodreads$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Smaller user base and community compared to mainstream tracking apps$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$No official managed/hosted version for non-technical users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Mobile experience depends on the web interface rather than dedicated native apps$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Is Jelu free to use$q$, $q$Yes, Jelu is completely free and open source; the only cost is whatever server infrastructure you self-host it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$How do I install Jelu$q$, $q$Jelu is most commonly deployed via Docker on a home server, NAS, or small VPS, following the setup instructions in its documentation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Does Jelu have an API$q$, $q$Yes, Jelu exposes a documented REST API that lets users programmatically add, update, and query their book data.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Can I import my existing book library into Jelu$q$, $q$Yes, Jelu supports importing collections from common export formats used by other book-tracking tools.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$How is Jelu different from Goodreads$q$, $q$Jelu is self-hosted, open source, ad-free, and API-accessible, while Goodreads is a centralized, Amazon-owned commercial service with a large social community but no self-hosting option.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Who maintains Jelu$q$, $q$Jelu is maintained by a developer known as bayang, with its source code published openly for self-hosting and contribution.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Private, ad-free reading log$q$, $q$Readers track their books, ratings, and reading history without ads, tracking, or a third-party company owning their data.$q$, $q$Privacy-conscious individual readers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Home-lab library companion$q$, $q$Self-hosting enthusiasts run Jelu alongside other self-hosted services like Jellyfin or Immich as part of their personal server stack.$q$, $q$Home-lab and self-hosting enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Custom reading-data tooling$q$, $q$Developers use Jelu's REST API to build custom dashboards, visualizations, or automations on top of their reading history.$q$, $q$Developers and technically inclined readers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full application source code","Unlimited books and reading history","REST API access","Docker deployment"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jelu is a free, open-source book tracking application designed to be self-hosted, giving readers a private, ad-free alternative to commercial services like Goodreads for logging what they have read, are reading, and plan to read next. It is maintained by a developer known as bayang and distributed openly for anyone to deploy on their own server.$q$, $q$Built with a Kotlin/Spring Boot backend and a Vue.js frontend, Jelu is most commonly deployed via Docker on a home server, NAS, or small VPS, fitting naturally alongside other self-hosted services like media servers or RSS readers that privacy-conscious users already run.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jelu lets users track books across reading statuses (to-read, reading, read, dropped), attach personal ratings and notes, organize titles into series and by custom tags, and log reading events over time to visualize reading pace and habits. Metadata import pulls in book details like cover art, author, and description from external sources so users don't have to enter every field by hand.$q$, $q$A documented REST API exposes the underlying data, letting technically inclined users build custom dashboards, scripts, or integrations on top of their reading library, and Jelu supports importing existing collections from common export formats to ease migration away from other tracking tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jelu is completely free and open source, with no license fee, subscription, or paid tier of any kind; the software itself costs nothing to download, run, and modify.$q$, $q$Because it is self-hosted, the only real cost is the infrastructure a user chooses to run it on, whether that is a spare home server, a NAS, or a low-cost VPS, making total ownership cost minimal and fully within the user's control.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ae515eae-68cb-450f-8fad-3f3174591ee1', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$AI autocomplete for academic writing$q$, $q$Context-aware sentence and paragraph suggestions tuned for academic tone and structure.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$1,700+ citation styles$q$, $q$Automatic citation formatting across major academic style guides including APA, MLA, Chicago, and Harvard.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Document library and PDF chat$q$, $q$Upload research papers and chat with an AI grounded in those sources to pull cited content into your draft.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$AI-assisted paraphrasing$q$, $q$Rewrite and rephrase text while preserving meaning and academic tone.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Outline generation$q$, $q$Generate a structured outline before drafting to organize arguments and sections.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Reference manager integration$q$, $q$Connects with Zotero and Mendeley for streamlined citation management.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Full document export$q$, $q$Export finished drafts in standard document formats for submission.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$AI review tool$q$, $q$Get AI-generated feedback and review passes on drafted sections.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Purpose-built for academic writing rather than general content$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Extensive citation style support with reference manager integrations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Free plan available with no credit card required$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$PDF-grounded AI chat reduces generic or unsupported claims$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Fast growth and profitability suggest a stable, well-run product$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Free plan usage limits are fairly restrictive for daily heavy use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Pro plan pricing adds up for students on a tight budget$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Primarily focused on academic use cases, less suited to general content writing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$AI-generated academic text raises institutional integrity policy questions at some schools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Bootstrapped company with less public transparency than VC-backed competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$What is Jenni AI used for$q$, $q$Jenni AI is an AI writing assistant built for academic and research writing, offering AI autocomplete, citation generation, PDF-grounded chat, and paraphrasing tools.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Who founded Jenni AI$q$, $q$Jenni AI was founded in 2019 by David Park, with Henry Mao later joining as technical co-founder to help pivot the product toward academic writing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$How much does Jenni AI cost$q$, $q$Jenni AI has a free plan with daily usage limits, a Plus plan at 12 dollars per month, and a Pro plan at 29 dollars per month with unlimited usage; institutions get custom pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Does Jenni AI support citation styles like APA and MLA$q$, $q$Yes, Jenni AI supports more than 1,700 citation styles, including APA, MLA, Chicago, and Harvard, and integrates with Zotero and Mendeley.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Is Jenni AI free to use$q$, $q$Yes, Jenni AI offers a free plan with limited daily autocompletes, PDF uploads, AI edits, and chat messages, requiring no credit card.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$How is Jenni AI different from Grammarly or QuillBot$q$, $q$Jenni AI is built specifically for academic writing with citation generation and PDF-grounded research tools, while Grammarly focuses on general grammar and style and QuillBot focuses primarily on paraphrasing.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Drafting a thesis or dissertation$q$, $q$Graduate students upload their literature review sources and use AI autocomplete and citation tools to draft chapters faster while keeping citations accurate.$q$, $q$Graduate students and PhD researchers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Writing research papers with grounded sources$q$, $q$Researchers chat with an AI grounded in their uploaded PDFs to pull relevant findings directly into a manuscript draft.$q$, $q$Academic researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Supporting institutional academic writing programs$q$, $q$Universities license Team and Institutional plans to give writing centers and research groups shared access with usage analytics.$q$, $q$University writing centers and research departments$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["10 AI autocompletes per day","10 PDF uploads per day","3 AI edits","5 AI chat messages","Unlimited citations across 10,000+ styles"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Plus$q$, $q$$12/month$q$, $q$Monthly$q$, NULL, $q$["5,000 autocompletes per month","Unlimited PDF uploads","500 AI edits and chat messages per month","Full document export","Live chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Pro$q$, $q$$29/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited AI autocomplete","Unlimited PDF uploads and AI edits","Unlimited AI chat and reviews","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Team and Institutional$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["Multi-seat licensing","Usage analytics","Dedicated onboarding","Custom institutional agreements"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jenni AI is an AI writing assistant designed specifically for academic and research writing rather than general-purpose content. Instead of just generating text from a prompt, it grounds its suggestions in documents a user uploads, such as journal articles and PDFs, and formats citations automatically as the draft is written.$q$, $q$The company was founded in 2019 by David Park, originally as an SEO copywriting tool built on GPT-2. After years of iteration, Park and co-founder Henry Mao repositioned the product around academic writing, layering in a citation engine and a document library so students and researchers could draft with sources already integrated rather than adding citations after the fact.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the center of Jenni AI is an AI autocomplete tuned for academic tone that suggests the next sentence or paragraph as a user types, alongside an AI chat that can answer questions about uploaded PDFs and pull relevant quotes or data directly into the draft. The citation system supports more than 1,700 styles, covers the major academic formats (APA, MLA, Chicago, Harvard), and integrates with reference managers like Zotero and Mendeley.$q$, $q$Additional tools include AI-assisted paraphrasing and rewriting, outline generation for structuring a paper before drafting begins, and full document export once writing is complete. Because suggestions are grounded in the user's own uploaded research library rather than generic web text, Jenni AI is positioned to reduce both hallucinated claims and citation errors compared with general-purpose AI writing tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jenni AI uses a three-tier freemium model. The Free plan allows 10 autocompletes and 10 PDF uploads per day with limited AI edits, chat messages, and reviews, plus unlimited citations across more than 10,000 styles, making it usable for light, occasional drafting.$q$, $q$Paid plans remove most usage caps: Plus is 12 dollars per month with 5,000 monthly autocompletes and unlimited PDF uploads, while Pro at 29 dollars per month removes all caps for unlimited autocomplete, edits, chat, and reviews plus priority support. A separate custom-priced Team and Institutional plan is available for universities and research groups needing multi-seat licensing and usage analytics.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('71403b09-3361-45de-9911-89b692d11395', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('71403b09-3361-45de-9911-89b692d11395', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
