INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Intelligent code completion$q$, $q$Context-aware suggestions based on deep static analysis of the surrounding code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Safe automated refactoring$q$, $q$Rename, extract, and restructure code across an entire project with confidence.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Integrated debugger$q$, $q$Full-featured debugging with breakpoints, evaluation, and step-through execution.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Framework support$q$, $q$Deep integration with Spring, Jakarta EE, Hibernate, Micronaut, and Quarkus for enterprise Java development.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Built-in database tools$q$, $q$Query, browse, and manage databases directly inside the IDE.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Multi-language support$q$, $q$Extended editing support for Java, Kotlin, Python, JavaScript, TypeScript, PHP, Go, Ruby, and SQL.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Version control integration$q$, $q$Native Git, GitHub, and other VCS support built directly into the workflow.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Build tool integration$q$, $q$Native support for Maven, Gradle, and other JVM build systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Deep, accurate static analysis and code intelligence$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Extensive, safe automated refactoring capabilities$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Core Java and Kotlin features now free for all use under the unified edition$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Strong framework support for Spring and enterprise Java stacks$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Large plugin ecosystem and active JetBrains development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Ultimate-tier features require an ongoing paid subscription$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Resource-intensive, can be slower than lightweight editors on modest hardware$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Subscription model means ongoing cost versus one-time purchase alternatives$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Steeper learning curve than simpler editors for beginners$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Recent price increase raised the cost of continued subscriptions$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Is IntelliJ IDEA free$q$, $q$Yes, since the unified 2025.3 release IntelliJ IDEA is free for both commercial and non-commercial use, with core Java and Kotlin features included; previously Ultimate-only capabilities require a paid subscription to unlock.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Who makes IntelliJ IDEA$q$, $q$IntelliJ IDEA is made by JetBrains, a company founded in 2000 in Prague, Czech Republic, by Sergey Dmitriev, Valentin Kipyatkov, and Eugene Belyaev.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$How much does IntelliJ IDEA Ultimate cost$q$, $q$An individual subscription unlocking Ultimate-tier features costs 199 dollars per year, or 19.90 dollars per month, with loyalty discounts in later renewal years.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$What is the difference between IntelliJ IDEA Community and Ultimate$q$, $q$Historically Community supported Java, Kotlin, Groovy, and Scala with basic frameworks for free, while Ultimate added extra languages and enterprise framework support; as of December 2025 both live in one unified installation gated by subscription.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Does IntelliJ IDEA support Kotlin$q$, $q$Yes, IntelliJ IDEA has first-class Kotlin support since JetBrains created and maintains the Kotlin programming language itself.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$What are the main alternatives to IntelliJ IDEA$q$, $q$Common alternatives include Eclipse, Visual Studio Code with Java extensions, NetBeans, and Android Studio, which is itself built on the IntelliJ platform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Enterprise Java backend development$q$, $q$Development teams building Spring Boot microservices use IntelliJ IDEA's framework-aware tooling and database tools to move faster with fewer errors.$q$, $q$Enterprise Java and Kotlin engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Learning Java or Kotlin$q$, $q$Students and self-taught developers use the free core edition to learn language fundamentals with strong code assistance.$q$, $q$Students and beginner developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Full-stack development with mixed languages$q$, $q$Developers working across backend Java/Kotlin and frontend JavaScript/TypeScript use Ultimate-tier language support in one IDE.$q$, $q$Full-stack developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$IntelliJ IDEA (Free core)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Java and Kotlin support","Code completion and inspections","Basic refactoring","Version control integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Individual subscription$q$, $q$$199/year ($19.90/month)$q$, $q$Annual or monthly$q$, NULL, $q$["Extended language support (Python, JS, PHP, Go, SQL)","Framework support (Spring, Jakarta EE, Micronaut)","Built-in database tools","Loyalty discounts in years 2 and 3"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$Organization subscription$q$, $q$Custom per-seat pricing$q$, $q$Annual$q$, NULL, $q$["Commercial-use license","Volume discounts","Centralized license management","All Products Pack option"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$IntelliJ IDEA is JetBrains' flagship integrated development environment, first released in January 2001 and built primarily around Java and Kotlin development. It is widely credited within the Java community for introducing deep, static-analysis-driven productivity features, such as on-the-fly code inspection and safe automated refactoring, that later became standard expectations across modern IDEs.$q$, $q$JetBrains, the company behind IntelliJ IDEA, was founded in 2000 in Prague by Sergey Dmitriev, Valentin Kipyatkov, and Eugene Belyaev. The company remains headquartered in Prague and has grown into one of the most respected developer-tools vendors globally, also building PyCharm, WebStorm, PhpStorm, GoLand, Rider, CLion, and the Kotlin programming language, which Google designated an official language for Android development.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$IntelliJ IDEA provides intelligent, context-aware code completion, real-time code inspection and quick-fixes, and a large library of safe automated refactorings that can rename, extract, or restructure code across an entire project with confidence. It includes a full-featured debugger, native support for build tools like Maven and Gradle, integrated version control, and a built-in terminal.$q$, $q$Historically the Ultimate Edition added support for additional languages (PHP, JavaScript, TypeScript, Python, Go, Ruby, SQL) and enterprise frameworks such as Spring, Jakarta EE, Hibernate, Micronaut, and Quarkus, plus built-in database tools and Android development support; as of the December 2025 unified release, these capabilities live inside a single IntelliJ IDEA install and are unlocked by an active subscription rather than requiring a separate paid product.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5a9d90c-49e0-401c-af66-b1fa6982ad32', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Since the unified 2025.3 release, IntelliJ IDEA is free to download and use for both commercial and non-commercial projects, with an expanded set of core Java and Kotlin features available at no cost. Previously Ultimate-only capabilities, such as extended language and framework support, now require an active JetBrains subscription to unlock inside the same installation.$q$, $q$An individual (personal-use) subscription costs 199 dollars per year, or 19.90 dollars per month, with loyalty discounts reducing the price to 159 dollars in year two and 119 dollars in year three of continuous subscription. Organizations pay a higher per-seat commercial rate, and JetBrains also sells an All Products Pack bundling every JetBrains IDE under one subscription; students, teachers, and open-source maintainers can qualify for free licenses.$q$]::text[], 2);
