INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Universal package format support$q$, $q$Natively manages 50+ package types including Maven, npm, PyPI, Docker, Helm, NuGet, RPM, and Terraform.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Public registry proxying$q$, $q$Caches and proxies public repositories so developers never pull dependencies directly from the open internet.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Security and vulnerability scanning$q$, $q$Identifies and blocks vulnerable or non-compliant artifacts, often paired with JFrog Xray.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Role-based access control$q$, $q$Fine-grained permissions with LDAP and SAML integration for enterprise identity systems.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Build and dependency caching$q$, $q$Speeds up CI/CD pipelines by caching dependencies and build outputs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Bi-directional replication$q$, $q$Automatically synchronizes repositories across geographically distributed teams and data centers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$REST API and JFrog CLI$q$, $q$Automate artifact management and integrate with any CI/CD or scripting workflow.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$CI/CD integrations$q$, $q$Native integration with Jenkins, GitHub Actions, Azure DevOps, and other major build systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Broadest package-format support among universal repository managers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Enterprise-grade security and governance features$q$, 1);
