INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Can be complex to configure and administer at scale$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Self-hosted licensing costs are significant for large deployments$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Full security capabilities require pairing with the separately priced Xray product$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$What is JFrog Artifactory used for$q$, $q$JFrog Artifactory is used to store, manage, secure, and distribute software artifacts such as packages, container images, and build outputs across an organization's CI/CD pipeline.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Is JFrog Artifactory free$q$, $q$Yes, JFrog offers a free Community Edition and an OSS edition for individual developers and open-source projects; commercial Pro, Pro X, Enterprise X, and Enterprise+ editions require payment.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Who founded JFrog$q$, $q$JFrog was founded in 2008 in Netanya, Israel by Shlomi Ben Haim, Yoav Landman, and Fred Simon.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Is JFrog a public company$q$, $q$Yes, JFrog went public on Nasdaq under the ticker FROG in September 2020, raising approximately 509 million dollars at an IPO valuation of about 3.9 billion dollars.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$How much does JFrog Artifactory cost$q$, $q$Cloud Pro plans typically start around 150 to 300 dollars per month, Enterprise X runs around 950 dollars per month, and self-hosted licenses range from about 20,000 to 250,000-plus dollars annually depending on scale.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$What are the main alternatives to JFrog Artifactory$q$, $q$Common alternatives include Sonatype Nexus Repository, AWS CodeArtifact, Azure Artifacts, Google Artifact Registry, and Cloudsmith.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Consolidating fragmented package repositories$q$, $q$DevOps teams replace multiple format-specific repositories with one governed Artifactory instance supporting all their package types.$q$, $q$DevOps and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Securing the software supply chain$q$, $q$Security teams use Artifactory to proxy public registries and block vulnerable artifacts before they reach production builds.$q$, $q$Application security and platform security teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Scaling CI/CD across global teams$q$, $q$Enterprises with distributed development centers use bi-directional replication to keep artifacts synchronized and builds fast worldwide.$q$, $q$Enterprise engineering organizations with global teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Community/OSS$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Core repository management","Limited package format support","Community support","Self-hosted only"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Pro$q$, $q$From approx. $150/month$q$, $q$Monthly or annual$q$, NULL, $q$["50+ package types","Cloud or self-hosted deployment","Basic security features","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Enterprise X$q$, $q$Approx. $950/month$q$, $q$Annual$q$, NULL, $q$["High availability","Advanced security and replication","Priority support","Expanded storage and transfer"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$Enterprise+$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["Full JFrog Platform access","Dedicated support and SLAs","Advanced distribution and governance","Custom deployment options"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$JFrog Artifactory is a universal repository manager: a single system for storing, versioning, securing, and distributing every kind of software artifact a development organization produces or consumes, from compiled Maven and npm packages to Docker images, Helm charts, and increasingly AI/ML model files. Instead of running separate, format-specific repositories, teams consolidate everything into one governed platform.$q$, $q$JFrog was founded in 2008 in Netanya, Israel by Shlomi Ben Haim, Yoav Landman, and Fred Simon, releasing the first version of Artifactory as an open-source Maven repository manager that year. The company relocated its main headquarters to Sunnyvale, California in 2012 to access Silicon Valley talent and customers, and went public on Nasdaq under the ticker FROG in September 2020, raising roughly 509 million dollars at an approximately 3.9 billion dollar valuation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Artifactory natively supports more than 50 package types, including Maven, npm, PyPI, Docker, Helm, NuGet, Debian, RPM, and Terraform, giving organizations a single source of truth for artifacts that would otherwise be scattered across format-specific tools. It proxies public package registries so developers never pull dependencies directly from the open internet, reducing exposure to supply-chain attacks and upstream outages, and offers dependency and build caching that measurably speeds up CI/CD pipelines.$q$, $q$Enterprise governance features include role-based access control, LDAP and SAML authentication, vulnerability identification and blocking (often paired with the companion Xray security scanning product), and automated bi-directional replication for globally distributed development teams. Artifactory integrates through REST APIs and the JFrog CLI with CI/CD systems like Jenkins, GitHub Actions, and Azure DevOps, and JFrog's managed cloud offering carries a 99.99 percent uptime SLA.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed99d703-32ed-4261-9895-3b1e2b391d3a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$JFrog offers free Community Edition and OSS tiers aimed at individual developers and open-source projects, alongside commercial Pro and Pro X editions for growing teams; cloud Pro plans typically start around 150 to 300 dollars per month for modest storage and transfer allowances. Larger organizations move to Enterprise X, priced around 950 dollars per month, or fully custom Enterprise+ agreements that add high availability, advanced security, and distribution features.$q$, $q$Self-hosted deployments are typically sold as annual subscriptions, ranging from roughly 20,000 to 75,000 dollars for small-to-mid-sized organizations up to 75,000 to 250,000-plus dollars for large enterprise deployments, with cloud storage overage commonly billed near 1.25 dollars per gigabyte, generally higher than pure-play competitors like Sonatype Nexus or cloud-native services such as AWS CodeArtifact.$q$]::text[], 2);
